sys_script_fix.script:
var randomDate;
var recordNumberMax = 5;
var recordNumberMin = 1;

// Variables for the costs generation
var generatePaid;
var generateOperationalCost;
var operationalReturn;

var currentDate = new GlideDate();

function createDeviceCosts(box_ref, op_return, op_cost, paid, date) {
    var logs = new GlideRecord("u_ev_costs");
    logs.initialize();
    logs.u_ev_box = box_ref;
    logs.u_operational_return = op_return;
    logs.u_operational_cost = op_cost;
    logs.u_paid = paid;
    logs.u_operation_date = date;
    logs.insert();
}

// Generate FLOAT random number for the cost fields
function randomFloatCost(min, max) { // min and max included 
    return (Math.random() * (max - min) + min).toFixed(2);
}

// Generate INT random number for the cost record per device
function getRandomNumber(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

function generateCosts(baseDeviceCost) {
    // Currency field is an Object so we need to change it to the float number with .00 fixed
    var baseCostFloat = parseFloat(baseDeviceCost.toString());
    generatePaid = randomFloatCost(20.00, 120.00);
    generateOperationalCost = randomFloatCost(baseCostFloat, 10.00);
    operationalReturn = (generatePaid - generateOperationalCost).toFixed(2);
}

var evDevice = new GlideRecord('u_ev_devices');
evDevice.addActiveQuery();
evDevice.query();

while (evDevice.next()) {
    var recordNumber = getRandomNumber(recordNumberMin, recordNumberMax);
    for (var i = 0; i < recordNumber; i++) {
        generateCosts(evDevice.u_single_use_cost);
        /*
        // For debugging only!
        gs.log('Device sys id:' + evDevice.sys_id);
        gs.log('Operational Return ' + operationalReturn);
        gs.log('Operational Cost ' + generateOperationalCost);
        gs.log('Paid ' + generatePaid);
        gs.log("Date " + randomDate);
        */
        createDeviceCosts(evDevice.sys_id, operationalReturn, generateOperationalCost, generatePaid, currentDate);
    }
}
